parameters.jsCode:
// Process and Enrich Sensor Data
const sensorData = $input.first().json;

// Add timestamp and building zone
const enrichedData = {
  ...sensorData,
  timestamp: $now.toISO(),
  building_zone: sensorData.zone || 'Main Hall',
  sensor_id: sensorData.sensor_id || 'SENS-' + Math.floor(Math.random() * 1000),
  is_after_hours: new Date().getHours() < 8 || new Date().getHours() > 18
};

return [{ json: enrichedData }];

